3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	type NeighborCount = { cell: Cell; count: number };
15	
16	const countLiveNeighbors = (liveCells: Cell[]): Map<string, NeighborCount> => {
17	  const counts = new Map<string, NeighborCount>();
18	  for (const cell of liveCells) {
19	    for (const neighbor of neighborsOf(cell)) {
20	      const k = cellKey(neighbor);
21	      const prior = counts.get(k)?.count ?? 0;
22	      counts.set(k, { cell: neighbor, count: prior + 1 });
23	    }
24	  }
25	  return counts;
26	};
27	
28	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
29	  const liveSet = new Set(liveCells.map(cellKey));
30	  const isAlive = (cell: Cell): boolean => liveSet.has(cellKey(cell));
31	  const survivesOrBorn = ({ cell, count }: NeighborCount): boolean =>
32	    count === 3 || (count === 2 && isAlive(cell));
33	
34	  return [...countLiveNeighbors(liveCells).values()]
35	    .filter(survivesOrBorn)
36	    .map(({ cell }) => cell);
