type NeighborCount = { cell: Cell; count: number };

const countLiveNeighbors = (liveCells: Cell[]): Map<string, NeighborCount> => {
  const counts = new Map<string, NeighborCount>();
  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = cellKey(neighbor);
      const prior = counts.get(k)?.count ?? 0;
      counts.set(k, { cell: neighbor, count: prior + 1 });
    }
  }
  return counts;
};

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveSet = new Set(liveCells.map(cellKey));
  const isAlive = (cell: Cell): boolean => liveSet.has(cellKey(cell));
  const survivesOrBorn = ({ cell, count }: NeighborCount): boolean =>
    count === 3 || (count === 2 && isAlive(cell));

  return [...countLiveNeighbors(liveCells).values()]
    .filter(survivesOrBorn)
    .map(({ cell }) => cell);
};

